{% extends "_base/base.html.j2" %}

{#====================================================================
  LETTER STRUCTURE (not a line-item document). This file is the STRUCTURE.
  To design a new look: clone it and edit ONLY the css (the skin).
  Text uses {{ L.<key> }} (maintain via set_translation). Available
  regions (data-box): recipient · info · subject · intro · body ·
  signature. Optional building block: contact_person (partial).
====================================================================#}

{% block title %}{{ data.subject | default(L.subject_fallback) }}{% endblock %}

{% set buyer = data.documentAddress | default({}) %}

{#- HEADER (Briefkopf): Logo + Firmenblock. Das ist DIE Kopfzeile — hier
   bearbeiten; KEINE zweite Kopfzeile im Inhalt zeichnen. Die Seitenzahl
   steht im Footer (css @bottom-center), nie oben rechts. Dieser Block
   ueberschreibt den Base-Default, damit der Header im Template sichtbar ist. -#}
{% block letterhead %}
  <div class="doc-header__brand">
    {% if assets.logo %}
      <img src="{{ assets.logo }}" alt="{{ data.company.name | default('') }}" class="doc-header__logo">
    {% else %}
      <div class="doc-header__wordmark"><strong>{{ data.company.name | default('') }}</strong></div>
    {% endif %}
    {% if data.company.address %}<p class="doc-header__sender">{{ data.company.address }}</p>{% endif %}
  </div>
  <div class="doc-header__contact">
    {% if data.company.phone %}<div>{{ data.company.phone }}</div>{% endif %}
    {% if data.company.email %}<div>{{ data.company.email }}</div>{% endif %}
    {% if data.company.website %}<div>{{ data.company.website }}</div>{% endif %}
  </div>
{% endblock %}

{% block content %}

  {#- Header row: recipient address left, metadata right. -#}
  <div class="head-cols">
    <div class="head-cols__addr">
      {% with buyer=buyer, title=L.doc_title %}
        {% include "_base/_partials/recipient.html.j2" %}
      {% endwith %}
    </div>
    <div class="head-cols__info">
      <section class="box-info" data-box="info" aria-labelledby="info-heading">
        <h2 id="info-heading" class="visually-hidden">{{ L.doc_title }}</h2>
        <table>
          <tbody>
            {% if data.documentDate %}<tr><th scope="row">{{ L.doc_date }}</th><td>{{ data.documentDate }}</td></tr>{% endif %}
            {% if data.customerNumber %}<tr><th scope="row">{{ L.customer_number }}</th><td>{{ data.customerNumber }}</td></tr>{% endif %}
            {% if data.customerOrderNumber %}<tr><th scope="row">{{ L.your_ref }}</th><td>{{ data.customerOrderNumber }}</td></tr>{% endif %}
          </tbody>
        </table>
      </section>
    </div>
  </div>

  {#- Subject (exactly one <h1>). -#}
  <section class="box-subject" data-box="subject">
    <h1>{{ data.subject | default(L.subject_fallback) }}</h1>
  </section>

  {#- Salutation. -#}
  {% if data.salutation %}
  <section class="box-intro" data-box="intro"><p>{{ data.salutation }}</p></section>
  {% endif %}

  {#- Free-text body. Paragraphs split on blank lines. -#}
  <section class="box-body" data-box="body">
    {% for para in (data.bodyText | default('')).split('\n\n') %}
      {% if para | trim %}<p>{{ para | trim }}</p>{% endif %}
    {% endfor %}
  </section>

  {#- Closing + signature. -#}
  <section class="box-signature" data-box="signature">
    <p class="sig-closing">{{ L.closing }}</p>
    <div class="sig-line"></div>
    {% if data.signerName or data.company.ceo %}<p class="sig-name">{{ data.signerName | default(data.company.ceo) }}</p>{% endif %}
  </section>

{% endblock %}

