/* ===================================================================
   SKIN — this is where the LOOK is designed. Cascades after base.css
   and overrides its neutral defaults. The structure (html) stays untouched.
   =================================================================== */

/* :root { --fs-body: 10.5pt; --lh-body: 1.5; } */

/* --- Header: address left, metadata right --- */
.head-cols { display: flex; justify-content: space-between; align-items: flex-start; gap: 10mm; margin: 8mm 0 10mm; }
.head-cols__addr { flex: 1 1 auto; min-width: 0; }
.head-cols__addr .box-recipient { margin: 0; }
.head-cols__info { flex: 0 0 60mm; }
.head-cols__info .box-info { margin: 0; }
.head-cols__info .box-info table { width: 100%; border-collapse: collapse; }
.head-cols__info .box-info th { white-space: nowrap; padding: 0.6mm 4mm 0.6mm 0; }
.head-cols__info .box-info td { text-align: right; }

/* --- Letter body --- */
.box-subject h1 { font-size: 13pt; }
.box-body { margin: 5mm 0; }
.box-body p { margin: 0 0 3mm; }

/* --- Closing --- */
.box-signature { margin: 10mm 0 0; page-break-inside: avoid; }
.sig-closing { margin: 0 0 12mm; }
.sig-name { margin: 1.5mm 0 0; }

/* --- Page footer: page number BOTTOM (not top) + mandatory legal/contact
   lines via @page margin boxes. Literal placeholder strings — CSS is NOT
   Jinja-rendered, so fill from the tenant's company data at author time,
   one line per \A. --- */
@page {
  @top-right { content: none; }
  @bottom-left {
    content: "Beispiel Handels GmbH \00b7 Marktplatz 1, 10115 Berlin \A Amtsgericht Charlottenburg \00b7 HRB 123456 \A Gesch\00e4ftsf\00fchrer: Max Beispiel";
    font-size: 6.5pt; line-height: 1.4; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line; vertical-align: top; padding-top: 4mm;
  }
  @bottom-center {
    content: "Seite " counter(page) " von " counter(pages);
    font-size: 6.5pt; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; vertical-align: top; padding-top: 4mm;
  }
  @bottom-right {
    content: "USt-IdNr. DE123456789 \A Commerzbank Berlin \00b7 IBAN DE89 3704 0044 0532 0130 00";
    font-size: 6.5pt; line-height: 1.4; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm;
  }
}
